CREATE TABLE "month" (
	"id" integer PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY (sequence name "month_id_seq" INCREMENT BY 1 MINVALUE 1 MAXVALUE 2147483647 START WITH 1 CACHE 1),
	"name" text NOT NULL,
	"number" integer,
	"start_date" date NOT NULL,
	"end_date" date NOT NULL,
	"sgk5510_employee_share_rate" numeric(6, 4) DEFAULT 0.14,
