	"sgk5510_employer_share_rate" numeric(6, 4) DEFAULT 0.2175,
	"sgk5510_employer_unemployment_share_rate" numeric(4, 2) DEFAULT 0.03,
	"sgk5746_employer_share_rate" numeric(6, 4) DEFAULT 0.2175,
